:root {
    --bg-color: #0f172a;
    --card-bg: #1e293b;
    --text-primary: #f8fafc;
    --text-secondary: #94a3b8;
    --accent-color: #38bdf8;
    --accent-color-2: #818cf8;
    --success-color: #22c55e;
    --error-color: #ef4444;
    --border-color: #334155;
}

* {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

body {
    background-color: var(--bg-color);
    color: var(--text-primary);
    font-family: 'Inter', system-ui, -apple-system, sans-serif;
    line-height: 1.5;
    padding: 20px;
}

.container {
    max-width: 1200px;
    margin: 0 auto;
}

header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 30px;
    padding-bottom: 20px;
    border-bottom: 1px solid var(--border-color);
}

h1 {
    font-size: 1.8rem;
    font-weight: 700;
    background: linear-gradient(to right, var(--accent-color), var(--accent-color-2));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
}

header h1 {
    -webkit-text-fill-color: initial; /* Fix for gradient text background-clip in some browsers if needed or just use standard */
}

/* Re-doing header h1 correctly */
header h1 {
    font-size: 1.8rem;
    font-weight: 700;
    color: var(--text-primary);
}

#status-indicator {
    display: flex;
    align-items: center;
    font-size: 0.875rem;
    color: var(--text-secondary);
}

.dot {
    height: 8px;
    width: 8px;
    background-color: var(--success-color);
    border-radius: 50%;
    display: inline-block;
    margin-right: 8px;
    box-shadow: 0 0 8px var(--success-color);
    animation: pulse 2s infinite;
}

@keyframes pulse {
    0% { opacity: 1; }
    50% { opacity: 0.4; }
    100% { opacity: 1; }
}

.dashboard-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(450px, 1fr));
    gap: 24px;
}

.card {
    background-color: var(--card-bg);
    border: 1px solid var(--border-color);
    border-radius: 12px;
    padding: 24px;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
}

.card h2 {
    font-size: 1.1rem;
    font-weight: 600;
    color: var(--text-secondary);
    margin-bottom: 20px;
}

canvas {
    width: 100% !important;
    height: 300px !important;
}

@media (max-width: 640px) {
    .dashboard-grid {
        grid-template-columns: 1fr;
    }
}

const API_URL = '/api/metrics';
const REFRESH_INTERVAL = 10000; // 10 seconds

let usageChart;
let tempChart;

// History length for charts
const MAX_DATA_POINTS = 20;

async function fetchData() {
    try {
        const response = await fetch(API_URL);
        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        const data = await response.json();
        updateCharts(data);
    } catch (error) {
        console.error('Error fetching metrics:', error);
    }
}

function initCharts() {
    const commonOptions = {
        responsive: true,
        maintainAspectRatio: false,
        scales: {
            x: {
                display: false
            },
            y: {
                beginAtZero: true,
                max: 100,
                grid: {
                    color: 'rgba(255, 255, 255, 0.1)'
                },
                ticks: {
                    color: '#94a3b8'
                }
            }
        },
        plugins: {
            legend: {
                labels: {
                    color: '#f8fafc'
                }
            }
        },
        animation: {
            duration: 800
        }
    };

    const ctxUsage = document.getElementById('usageChart').getContext('2d');
    usageChart = new Chart(ctxUsage, {
        type: 'line',
        data: {
            labels: Array(MAX_DATA_POINTS).fill(''),
            datasets: [
                {
                    label: 'CPU Usage (%)',
                    borderColor: '#38bdf8',
                    backgroundColor: 'rgba(56, 189, 248, 0.1)',
                    data: Array(MAX_DATA_POINTS).fill(0),
                    fill: true,
                    tension: 0.4
                },
                {
                    label: 'Memory Usage (%)',
                    borderColor: '#818cf8',
                    backgroundColor: 'rgba(129, 140, 248, 0.1)',
                    data: Array(MAX_DATA_POINTS).fill(0),
                    fill: true,
                    tension: 0.4
                }
            ]
        },
        options: commonOptions
    });

    const ctxTemp = document.getElementById('tempChart').getContext('2d');
    tempChart = new Chart(ctxTemp, {
        type: 'line',
        data: {
            labels: Array(MAX_DATA_POINTS).fill(''),
            datasets: [
                {
                    label: 'CPU Temp (°C)',
                    borderColor: '#fb7185',
                    backgroundColor: 'rgba(251, 113, 133, 0.1)',
                    data: Array(MAX_DATA_POINTS).fill(0),
                    fill: true,
                    tension: 0.4
                },
                {
                    label: 'GPU Temp (°C)',
                    borderColor: '#fbbf24',
                    backgroundColor: 'rgba(251, 191, 36, 0.1)',
                    data: Array(MAX_DATA_POINTS).fill(0),
                    fill: true,
                    tension: 0.4
                }
            ]
        },
        options: {
            ...commonOptions,
            scales: {
                ...commonOptions.scales,
                y: {
                    ...commonOptions.scales.y,
                    max: 100 // Assuming temps don't exceed 100 for now, or adjust dynamically
                }
            }
        }
    });
}

function updateCharts(data) {
    // Expected data format: 
    // { 
    //   cpu_usage: number, 
    //   memory_usage: number, 
    //   cpu_temp: number, 
    //   gpu_temp: number 
    // }

    const timestamp = new Date().toLocaleTimeString();

    // Update Usage Chart
    usageChart.data.labels.push(timestamp);
    usageChart.data.labels.shift();
    usageChart.data.datasets[0].data.push(data.cpu_usage);
    usageChart.data.datasets[0].data.shift();
    usageChart.data.datasets[1].data.push(data.memory_usage);
    usageChart.data.datasets[1].data.shift();
    usageChart.update();

    // Update Temp Chart
    tempChart.data.labels.push(timestamp);
    tempChart.data.labels.shift();
    tempChart.data.datasets[0].data.push(data.cpu_temp);
    tempChart.data.datasets[0].data.shift();
    tempChart.data.datasets[1].data.push(data.gpu_temp);
    tempChart.data.datasets[1].data.shift();
    tempChart.update();
}

// Initialize
document.addEventListener('DOMContentLoaded', () => {
    initCharts();
    fetchData();
    setInterval(fetchData, REFRESH_INTERVAL);
});

